+/**
+ * Generic callback registry for lightweight, synchronous pub/sub.
+ *
+ * NOTE: The notification system uses EventBus exclusively (see CLAUDE.md ADR).
+ * This class is retained as a general-purpose utility for cases where a simple
+ * synchronous callback list is sufficient and EventBus would be overkill.
+ */
+export class CallbackRegistry {
+    callbacks = [];
+    /**
+     * Register a callback to be notified when events occur.
+     */
+    register(cb) {
+        this.callbacks.push(cb);
+        // Return unregister function
+        return () => {
+            const index = this.callbacks.indexOf(cb);
+            if (index >= 0) {
+                this.callbacks.splice(index, 1);
+            }
+        };
+    }
+    /**
+     * Notify all registered callbacks with the given data.
+     */
+    notify(data) {
+        for (const cb of this.callbacks) {
+            cb(data);
+        }
+    }
+    /**
+     * Get the number of registered callbacks.
+     */
+    get size() {
+        return this.callbacks.length;
+    }
+    /**
+     * Clear all registered callbacks.
+     */
+    clear() {
+        this.callbacks = [];
+    }
+}
+//# sourceMappingURL=callback-registry.js.map
