+/**
+ * Email notification handler — formats and dispatches email notifications
+ * in response to order lifecycle events.
+ *
+ * Follows the same event-driven pattern as NotificationService:
+ * subscribes to EventBus events and handles them independently,
+ * keeping the email channel decoupled from event producers.
+ *
+ * Depends on:
+ * - EventBus (event system) for receiving order lifecycle events
+ */
+
+import type { EventBus } from '../events/event-bus.js';
+import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
+import type { OrderStatus } from '../models/order.js';
+import { Logger } from '../utils/logger.js';
+
+export interface EmailMessage {
+  id: string;
+  to: string;
+  from: string;
+  subject: string;
+  html: string;
+  sentAt: Date;
+}
+
+const DEFAULT_FROM = 'orders@taskflowpro.com';
+
+let nextId = 1;
+
+function generateEmailId(): string {
+  return `email-${String(nextId++).padStart(4, '0')}`;
+}
+
+export function resetEmailIdCounter(): void {
+  nextId = 1;
+}
+
+const STATUS_LABELS: Record<OrderStatus, string> = {
+  pending: 'Pending',
+  confirmed: 'Confirmed',
+  shipped: 'Shipped',
+  delivered: 'Delivered',
+  cancelled: 'Cancelled',
+};
+
+export class EmailNotificationHandler {
+  private logger = new Logger('EmailNotificationHandler');
+  private sentEmails: EmailMessage[] = [];
+
+  constructor(private eventBus: EventBus) {
+    this.registerHandlers();
+  }
+
+  /**
+   * Register EventBus handlers for order email notifications.
+   */
+  private registerHandlers(): void {
+    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
+      this.handleOrderCreated(event);
+    });
+
+    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
+      this.handleOrderStatusChanged(event);
+    });
+  }
+
+  /**
+   * Handle order created — send order confirmation email.
+   */
+  private handleOrderCreated(event: OrderCreatedEvent): void {
+    this.logger.info(`Sending order confirmation email for order ${event.order.id}`);
+
+    const itemRows = event.order.items
+      .map(
+        (item) =>
+          `<tr><td>${item.name}</td><td>${item.quantity}</td><td>$${item.unitPrice.toFixed(2)}</td><td>$${(item.quantity * item.unitPrice).toFixed(2)}</td></tr>`,
+      )
+      .join('');
+
+    const html = [
+      `<h1>Order Confirmation</h1>`,
+      `<p>Hi ${event.user.name},</p>`,
+      `<p>Thank you for your order <strong>${event.order.id}</strong>.</p>`,
+      `<table><thead><tr><th>Item</th><th>Qty</th><th>Price</th><th>Subtotal</th></tr></thead>`,
+      `<tbody>${itemRows}</tbody></table>`,
+      `<p><strong>Total: $${event.order.total.toFixed(2)}</strong></p>`,
+    ].join('');
+
+    this.sendEmail({
+      to: event.user.email,
+      subject: `Order Confirmation: ${event.order.id}`,
+      html,
+    });
+  }
+
+  /**
+   * Handle order status change — send status update email.
+   */
+  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
+    this.logger.info(
+      `Sending status update email for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
+    );
+
+    const newLabel = STATUS_LABELS[event.newStatus as OrderStatus] ?? event.newStatus;
+    const previousLabel = STATUS_LABELS[event.previousStatus as OrderStatus] ?? event.previousStatus;
+
+    const html = [
+      `<h1>Order Status Update</h1>`,
+      `<p>Your order <strong>${event.order.id}</strong> has been updated.</p>`,
+      `<p>Status: <em>${previousLabel}</em> &rarr; <strong>${newLabel}</strong></p>`,
+      this.getStatusMessage(event.newStatus as OrderStatus, event.order.id),
+    ].join('');
+
+    this.sendEmail({
+      to: event.order.userId,
+      subject: `Order ${newLabel}: ${event.order.id}`,
+      html,
+    });
+  }
+
+  /**
+   * Get a contextual message for a given order status.
+   */
+  private getStatusMessage(status: OrderStatus, orderId: string): string {
+    switch (status) {
+      case 'confirmed':
+        return `<p>Your order ${orderId} has been confirmed and is being prepared.</p>`;
+      case 'shipped':
+        return `<p>Your order ${orderId} has been shipped and is on its way.</p>`;
+      case 'delivered':
+        return `<p>Your order ${orderId} has been delivered. Thank you for your purchase!</p>`;
+      case 'cancelled':
+        return `<p>Your order ${orderId} has been cancelled.</p>`;
+      default:
+        return '';
+    }
+  }
+
+  /**
+   * Send an email (in-memory for this demo).
+   */
+  private sendEmail(params: { to: string; subject: string; html: string }): void {
+    const email: EmailMessage = {
+      id: generateEmailId(),
+      to: params.to,
+      from: DEFAULT_FROM,
+      subject: params.subject,
+      html: params.html,
+      sentAt: new Date(),
+    };
+    this.sentEmails.push(email);
+    this.logger.info(`Email sent: ${email.id} to ${params.to}`);
+  }
+
+  /**
+   * Get all sent emails.
+   */
+  getSentEmails(): EmailMessage[] {
+    return [...this.sentEmails];
+  }
+
+  /**
+   * Get sent emails for a specific recipient.
+   */
+  getSentEmailsForRecipient(recipient: string): EmailMessage[] {
+    return this.sentEmails.filter((e) => e.to === recipient);
+  }
+
+  /**
+   * Get the count of sent emails.
+   */
+  getSentEmailCount(): number {
+    return this.sentEmails.length;
+  }
+
+  /**
+   * Clear all sent emails (useful for testing).
+   */
+  clearSentEmails(): void {
+    this.sentEmails = [];
+  }
+}

